    const businessOrder: string[] = ["electronics", "grocery", "pharmacy", "restaurant"];

    // Filter valid coupons
    const validCoupons: { code: string; businessLine: string; isActive: boolean }[] = [];
    for (let i = 0; i < code.length; i++) {
        const codeStr = code[i];
        const businessStr = businessLine[i];
        const isActiveBool = isActive[i];

        // Check if code is valid (non-empty, only alphanumeric and underscores)
        const codeValid = codeStr !== "" && /^[a-zA-Z0-9_]+$/.test(codeStr);
        // Check if business line is valid
        const businessValid = businessOrder.includes(businessStr);
        // Check if active
        const active = isActiveBool;

        if (codeValid && businessValid && active) {
            validCoupons.push({ code: codeStr, businessLine: businessStr, isActive: active });
        }
    }

    // Sort by business line order, then by code lexicographically
    validCoupons.sort((a, b) => {
        const businessIndexA = businessOrder.indexOf(a.businessLine);
        const businessIndexB = businessOrder.indexOf(b.businessLine);
        if (businessIndexA !== businessIndexB) {
            return businessIndexA - businessIndexB;
        }
        return a.code.localeCompare(b.code);
    });

    // Extract the codes in order
    const result: string[] = [];
    for (const coupon of validCoupons) {
        result.push(coupon.code);
    }

    return result;
}
